if flake8_output.exists():
    try:
        content = flake8_output.read_text()
        for line in content.strip().split('\n'):
            if line.strip() and ':' in line:
                parts = line.split(':', 3)
                if len(parts) >= 4:
                    linting_issues.append({'file': parts[0], 'line': int(parts[1]), 'code': parts[2].strip(), 'message': parts[3].strip(), 'tool': 'flake8'})
    except Exception:
        pass

if mypy_output.exists():
    try:
        content = mypy_output.read_text()
        for line in content.strip().split('\n'):
            if line.strip() and ':' in line:
                parts = line.split(':', 3)
                if len(parts) >= 4:
                    linting_issues.append({'file': parts[0], 'line': int(parts[1]), 'code': parts[2].strip(), 'message': parts[3].strip(), 'tool': 'mypy'})
    except Exception:
        pass

if black_output.exists():
    try:
        content = black_output.read_text()
        if 'would reformat' in content:
            linting_issues.append({'file': 'multiple', 'line': 0, 'code': 'BLACK001', 'message': 'Code formatting issues detected by Black', 'tool': 'black'})
    except Exception:
        pass

